
var modulePicker = require('./module-picker.js');

var gulp = require('gulp');
var concat = require('gulp-concat');
var map    = require('map-stream');

var uniqueFilterFn = function(item, idx, all) {
      return idx === all.indexOf(item);
    },
    dedupFn = function(file, cb) {
        // stackoverflow.com/questions/26852813/gulp-how-to-merge-files-without-lines-duplication

        // convert file buffer into a string
        var contents = file.contents.toString();

        // split it by lines
        var lines = contents.split(/;/);

        // apply the unique filter
        var uniqueLines = lines.filter(uniqueFilterFn);

        // join unique list into lines
        var output = uniqueLines.join(';');

        // convert string back into buffer
        var buffer = new Buffer(output, 'binary');

        // replace the file contents
        file.contents = buffer;

        // continue
        return cb(null, file);
    };

var concat_jsfiles =  function() {
    return gulp.src(modulePicker.generateSourceFiles(), {allowEmpty: true})
        .pipe(concat({ path: 'index.js', stat: { mode: 0666 }}))
        .pipe(map(dedupFn))
        .pipe(gulp.dest('./'));
}

gulp.task('scripts',concat_jsfiles);

concat_jsfiles();
exports.default = concat_jsfiles;
